"""v2 PID watcher — detects Claude processes that have died.

The watcher runs on a timer (config-driven cadence, same as the v1 discovery
loop). On each tick it:

1. Queries the watch set: distinct (pid, source_system, cwd) tuples from
   claude_log_hooks where source_system matches the local hostname AND no
   SessionEnd hook has fired for any of the tuple's sessions AND no
   claude_log_pid_deaths row exists yet.
2. For each tuple, asks the OS whether the PID exists.
3. When the OS reports the PID gone, inserts one row into
   claude_log_pid_deaths and broadcasts pid_death_logged on /ws/v2.

Death criterion is purely "no process at the PID" — image mismatch is not
checked, per docs/old/changes-with-v2.md. Source-of-truth is the absence
of the process, not its identity.

Cross-machine: the watcher only watches PIDs whose source_system is the
local hostname. Other hosts' PIDs are watched by their own agentpulse
instance.
"""

import asyncio
import logging
import socket
import time

import aiosqlite
import psutil

from agentpulse.api.v2.events import broadcast_pid_death_logged
from agentpulse.api.v2.ids import derive_process_id
from agentpulse.api.v2.queries._instance import _instance_started_at_for
from agentpulse.platforms.claude import schema

logger = logging.getLogger(__name__)


def _pid_exists(pid: int) -> bool:
    """Return True if the OS reports a process at this PID, else False."""
    try:
        return psutil.pid_exists(pid)
    except Exception:
        return False


async def _watch_set(
    db: aiosqlite.Connection, *, source_system: str
) -> list[tuple[int, str]]:
    """Identity tuples to check this tick.

    Returns (pid, cwd) pairs filtered per-hook-row, then DISTINCT-collapsed:

    - row's source_system matches the local hostname
    - row's pid > 0
    - row's session has no SessionEnd hook
    - no claude_log_pid_deaths row exists for the tuple with observed_at
      *after* the row's received_at — i.e. this hook is not already
      covered by a previous death

    The post-death-row check matters for PID reuse. After a PID dies and
    its death is recorded, the OS may hand the same PID to a new Claude
    instance later. The new instance's hooks have received_at later than
    the old death's observed_at, so they pass the filter and the tuple
    re-enters the watch set — its eventual death gets a new row.
    """
    cursor = await db.execute(
        """
        SELECT DISTINCT h.pid, h.cwd
        FROM claude_log_hooks h
        WHERE h.source_system = ?
              AND h.pid > 0
              AND NOT EXISTS (
                  SELECT 1 FROM claude_log_hooks e
                  WHERE e.session_id = h.session_id
                        AND e.event_name = 'SessionEnd'
              )
              AND NOT EXISTS (
                  SELECT 1 FROM claude_log_pid_deaths d
                  WHERE d.pid = h.pid
                        AND d.source_system = h.source_system
                        AND d.cwd = h.cwd
                        AND d.observed_at > h.received_at
              )
        """,
        (source_system,),
    )
    rows = await cursor.fetchall()
    return [(r["pid"], r["cwd"]) for r in rows]


async def run_pid_watcher_tick(db: aiosqlite.Connection) -> None:
    """One pass of the watcher: check the watch set, write deaths, broadcast."""
    source_system = socket.gethostname()
    targets = await _watch_set(db, source_system=source_system)
    logger.debug("pid watcher tick checking %d tuples", len(targets))

    for pid, cwd in targets:
        alive = await asyncio.to_thread(_pid_exists, pid)
        if alive:
            continue

        observed_at = time.time()
        log_id = await schema.insert_log_pid_death(
            db,
            pid=pid,
            source_system=source_system,
            cwd=cwd,
            observed_at=observed_at,
            observed_by="pid-watcher",
        )
        await db.commit()

        logger.info(
            "pid death detected pid=%d source_system=%s cwd=%s",
            pid,
            source_system,
            cwd,
        )

        # The dying instance's earliest activity is what we want to hash.
        # Pass observed_at to find activity in the (prior_death, infinity)
        # range — that's the instance that just died.
        earliest = await _instance_started_at_for(
            db,
            pid=pid,
            source_system=source_system,
            cwd=cwd,
            received_at=observed_at,
        )
        process_id = derive_process_id(
            source_system=source_system,
            pid=pid,
            cwd=cwd,
            earliest_received_at=earliest if earliest is not None else observed_at,
        )

        await broadcast_pid_death_logged(
            log_id=log_id,
            process_id=process_id,
            pid=pid,
            source_system=source_system,
            cwd=cwd,
            observed_at=observed_at,
            observed_by="pid-watcher",
        )
